const operation = String($json.operation ?? '')
  .trim()
  .toUpperCase();

const payload = $json.payload;

if (!operation) {
  throw new Error('AUDIT_REQUEST_INVALID: operation is required');
}

if (
  payload === null ||
  typeof payload !== 'object' ||
  Array.isArray(payload)
) {
  throw new Error('AUDIT_REQUEST_INVALID: payload must be an object');
}

return {
  json: {
    operation,
    payload,
  },
};

const run = $json.payload?.run;

if (!run || typeof run !== 'object' || Array.isArray(run)) {
  throw new Error('AUDIT_CREATE_RUN_INVALID: payload.run is required');
}

const requiredStringFields = [
  'run_id',
  'execution_id',
  'workflow_id',
  'workflow_name',
  'workflow_version',
  'environment',
  'correlation_id',
  'entity_type',
  'entity_id',
  'source_type',
  'source_event_id',
  'started_at',
  'status',
  'last_completed_step',
];

const invalidFields = requiredStringFields.filter((field) => {
  const value = run[field];
  return typeof value !== 'string' || value.trim() === '';
});

if (invalidFields.length > 0) {
  throw new Error(
    `AUDIT_CREATE_RUN_INVALID: missing or invalid fields: ${invalidFields.join(', ')}`
  );
}

const allowedEnvironments = new Set(['TEST', 'STAGING', 'PROD']);

if (!allowedEnvironments.has(run.environment)) {
  throw new Error(
    `AUDIT_CREATE_RUN_INVALID: unsupported environment "${run.environment}"`
  );
}

if (run.status !== 'RUNNING') {
  throw new Error(
    `AUDIT_CREATE_RUN_INVALID: initial status must be RUNNING`
  );
}

if (Number.isNaN(Date.parse(run.started_at))) {
  throw new Error(
    'AUDIT_CREATE_RUN_INVALID: started_at must be a valid ISO datetime'
  );
}

const retryCount = run.retry_count ?? 0;

if (!Number.isInteger(retryCount) || retryCount < 0) {
  throw new Error(
    'AUDIT_CREATE_RUN_INVALID: retry_count must be a non-negative integer'
  );
}

return {
  json: {
    operation: 'CREATE_RUN',
    run: {
      ...run,
      retry_count: retryCount,
    },
  },
};

const run = $('Validate CREATE_RUN').item.json.run;

return {
  json: {
    success: true,
    operation: 'CREATE_RUN',
    data: {
      run_id: run.run_id,
      status: run.status,
      persisted_at: $now.toISO(),
      storage: 'GOOGLE_SHEETS',
    },
    error: null,
  },
};

const event = $json.payload?.event;

if (!event || typeof event !== 'object' || Array.isArray(event)) {
  throw new Error(
    'AUDIT_APPEND_EVENT_INVALID: payload.event is required'
  );
}

const requiredStringFields = [
  'event_id',
  'run_id',
  'correlation_id',
  'occurred_at',
  'step',
  'service',
  'action',
  'status',
];

const invalidFields = requiredStringFields.filter((field) => {
  const value = event[field];
  return typeof value !== 'string' || value.trim() === '';
});

if (invalidFields.length > 0) {
  throw new Error(
    `AUDIT_APPEND_EVENT_INVALID: missing or invalid fields: ${invalidFields.join(', ')}`
  );
}

if (Number.isNaN(Date.parse(event.occurred_at))) {
  throw new Error(
    'AUDIT_APPEND_EVENT_INVALID: occurred_at must be a valid ISO datetime'
  );
}

const allowedStatuses = new Set([
  'STARTED',
  'SUCCESS',
  'FAILED',
  'SKIPPED',
]);

if (!allowedStatuses.has(event.status)) {
  throw new Error(
    `AUDIT_APPEND_EVENT_INVALID: unsupported status "${event.status}"`
  );
}

const durationMs = event.duration_ms ?? null;

if (
  durationMs !== null &&
  (!Number.isInteger(durationMs) || durationMs < 0)
) {
  throw new Error(
    'AUDIT_APPEND_EVENT_INVALID: duration_ms must be null or a non-negative integer'
  );
}

const resource = event.resource ?? null;

if (
  resource !== null &&
  (typeof resource !== 'object' || Array.isArray(resource))
) {
  throw new Error(
    'AUDIT_APPEND_EVENT_INVALID: resource must be null or an object'
  );
}

const metadata = event.metadata ?? {};

if (
  metadata === null ||
  typeof metadata !== 'object' ||
  Array.isArray(metadata)
) {
  throw new Error(
    'AUDIT_APPEND_EVENT_INVALID: metadata must be an object'
  );
}

return {
  json: {
    operation: 'APPEND_EVENT',
    event: {
      ...event,
      duration_ms: durationMs,
      resource,
      metadata,
      message: event.message ?? '',
    },
  },
};

const event = $('Validate APPEND_EVENT').item.json.event;
const resource = event.resource;

return {
  json: {
    event_id: event.event_id,
    run_id: event.run_id,
    correlation_id: event.correlation_id,
    occurred_at: event.occurred_at,
    step: event.step,
    service: event.service,
    action: event.action,
    status: event.status,

    resource_type: resource?.type ?? '',
    resource_id: resource?.id ?? '',
    resource_url: resource?.url ?? '',

    duration_ms: event.duration_ms ?? '',
    message: event.message,
    metadata_json: JSON.stringify(event.metadata),
  },
};

const event = $('Validate APPEND_EVENT').item.json.event;

return {
  json: {
    success: true,
    operation: 'APPEND_EVENT',
    data: {
      event_id: event.event_id,
      run_id: event.run_id,
      status: event.status,
      persisted_at: $now.toISO(),
      storage: 'GOOGLE_SHEETS',
    },
    error: null,
  },
};

const payload = $json.payload;

if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
  throw new Error('AUDIT_UPDATE_RUN_INVALID: payload is required');
}

const runId = payload.run_id;
const patch = payload.patch;

if (typeof runId !== 'string' || runId.trim() === '') {
  throw new Error('AUDIT_UPDATE_RUN_INVALID: run_id is required');
}

if (!patch || typeof patch !== 'object' || Array.isArray(patch)) {
  throw new Error('AUDIT_UPDATE_RUN_INVALID: patch must be an object');
}

const allowedFields = new Set([
  'status',
  'last_completed_step',
  'finished_at',
  'failed_step',
  'error_type',
  'error_code',
  'error_summary',
  'retry_count',
  'execution_url',
]);

const patchFields = Object.keys(patch);

if (patchFields.length === 0) {
  throw new Error('AUDIT_UPDATE_RUN_INVALID: patch cannot be empty');
}

const unsupportedFields = patchFields.filter(
  (field) => !allowedFields.has(field)
);

if (unsupportedFields.length > 0) {
  throw new Error(
    `AUDIT_UPDATE_RUN_INVALID: immutable or unsupported fields: ${unsupportedFields.join(', ')}`
  );
}

const allowedStatuses = new Set([
  'RUNNING',
  'SUCCESS',
  'VALIDATION_FAILED',
  'PARTIAL_FAILURE',
  'FAILED',
  'MANUAL_REVIEW_REQUIRED',
]);

if (
  patch.status !== undefined &&
  !allowedStatuses.has(patch.status)
) {
  throw new Error(
    `AUDIT_UPDATE_RUN_INVALID: unsupported status "${patch.status}"`
  );
}

if (
  patch.finished_at !== undefined &&
  patch.finished_at !== null &&
  Number.isNaN(Date.parse(patch.finished_at))
) {
  throw new Error(
    'AUDIT_UPDATE_RUN_INVALID: finished_at must be null or a valid ISO datetime'
  );
}

if (
  patch.retry_count !== undefined &&
  (!Number.isInteger(patch.retry_count) || patch.retry_count < 0)
) {
  throw new Error(
    'AUDIT_UPDATE_RUN_INVALID: retry_count must be a non-negative integer'
  );
}

return {
  json: {
    operation: 'UPDATE_RUN',
    run_id: runId.trim(),
    patch,
  },
};

const current = $json;
const request = $('Validate UPDATE_RUN').item.json;
const patch = request.patch;

if (current.run_id !== request.run_id) {
  throw new Error('AUDIT_UPDATE_RUN_CONFLICT: retrieved run does not match request');
}

const terminalStatuses = new Set([
  'SUCCESS',
  'VALIDATION_FAILED',
  'PARTIAL_FAILURE',
  'FAILED',
  'MANUAL_REVIEW_REQUIRED',
]);

const currentStatus = current.status;
const nextStatus = patch.status ?? currentStatus;

// Завершённый run нельзя переводить в другой статус.
// Повторный запуск должен создавать новый AutomationRun.
if (
  terminalStatuses.has(currentStatus) &&
  nextStatus !== currentStatus
) {
  throw new Error(
    `AUDIT_UPDATE_RUN_INVALID_TRANSITION: ${currentStatus} → ${nextStatus}`
  );
}

const updated = {
  ...current,
  ...patch,
};

if (nextStatus === 'RUNNING' && updated.finished_at) {
  throw new Error(
    'AUDIT_UPDATE_RUN_INVALID: RUNNING run cannot have finished_at'
  );
}

if (
  terminalStatuses.has(nextStatus) &&
  !updated.finished_at
) {
  throw new Error(
    `AUDIT_UPDATE_RUN_INVALID: ${nextStatus} requires finished_at`
  );
}

if (nextStatus === 'SUCCESS') {
  const errorFields = [
    updated.failed_step,
    updated.error_type,
    updated.error_code,
    updated.error_summary,
  ];

  if (errorFields.some((value) => value)) {
    throw new Error(
      'AUDIT_UPDATE_RUN_INVALID: SUCCESS run cannot contain failure data'
    );
  }
}

const failureStatuses = new Set([
  'VALIDATION_FAILED',
  'PARTIAL_FAILURE',
  'FAILED',
  'MANUAL_REVIEW_REQUIRED',
]);

if (
  failureStatuses.has(nextStatus) &&
  (!updated.failed_step || !updated.error_summary)
) {
  throw new Error(
    `AUDIT_UPDATE_RUN_INVALID: ${nextStatus} requires failed_step and error_summary`
  );
}

return {
  json: {
    run_id: current.run_id,
    execution_id: current.execution_id,
    workflow_id: current.workflow_id,
    workflow_name: current.workflow_name,
    workflow_version: current.workflow_version,
    environment: current.environment,
    correlation_id: current.correlation_id,
    entity_type: current.entity_type,
    entity_id: current.entity_id,
    source_type: current.source_type,
    source_event_id: current.source_event_id,
    started_at: current.started_at,

    finished_at: updated.finished_at ?? '',
    status: nextStatus,
    last_completed_step: updated.last_completed_step,

    failed_step: updated.failed_step ?? '',
    error_type: updated.error_type ?? '',
    error_code: updated.error_code ?? '',
    error_summary: updated.error_summary ?? '',

    retry_count: Number(updated.retry_count ?? 0),
    execution_url: updated.execution_url ?? '',
  },
};

const updated = $('Apply Run Patch').item.json;

return {
  json: {
    success: true,
    operation: 'UPDATE_RUN',
    data: {
      run_id: updated.run_id,
      status: updated.status,
      updated_at: $now.toISO(),
      storage: 'GOOGLE_SHEETS',
    },
    error: null,
  },
};
